#!/usr/bin/env python3
"""Generate random_update.c with 51 RANDOM_update_R functions (R in 0, 2, 4, ..., 100).

Each function performs exactly 100 random memory accesses (R reads, 100-R writes)
using an LFSR-based random walk (POLY=7). A nop(pause) call is inserted after
every 5 accesses (20 calls total per function invocation).

R/W interleave formula: is_read[slot] = ((slot * R) % 100) < R
Guarantees exactly R reads in 100 slots, read-first.
"""

HEADER = """\
/* Auto-generated by gen_random_update.py. Do not edit manually.
 *
 * 51 variants of RANDOM_update_R (R in {0, 2, 4, ..., 100}).
 * Each function: 100 accesses, 20 nop() calls (one after every 5 accesses).
 * LFSR step before each access: ran = (ran << 1) ^ ((int64_t)ran < 0 ? POLY : 0)
 * Read:  local += table[ran & mask]
 * Write: table[ran & mask] = 0
 * R/W interleave: is_read[slot] = ((slot * R) % 100) < R  (read-first, exactly R reads)
 */

#include "random_update.h"

"""

LFSR = "ran = (ran << 1) ^ ((int64_t)ran < 0 ? POLY : 0);"


def gen_function(R):
    reads = R
    writes = 100 - R
    lines = []
    lines.append(f"/* RANDOM_update_{R}: {reads} read(s) + {writes} write(s). */")
    lines.append(f"void RANDOM_update_{R}(volatile uint64_t *table, uint64_t mask,")
    lines.append(f"                       int *pause, uint64_t *ran_io, volatile uint64_t *sink)")
    lines.append("{")
    lines.append("    uint64_t ran = *ran_io;")
    lines.append("    uint64_t local = *sink;")

    for slot in range(100):
        if slot % 5 == 0:
            group_num = slot // 5 + 1
            lines.append(f"\n    /* group {group_num} */")

        is_read = ((slot * R) % 100) < R
        if is_read:
            access = f"local += table[ran & mask];"
            rw = "R"
        else:
            access = f"table[ran & mask] = 0;"
            rw = "W"
        lines.append(f"    {LFSR} {access} /* {rw} slot {slot} */")

        if (slot + 1) % 5 == 0:
            lines.append("    nop(pause);")

    lines.append("")
    lines.append("    *ran_io = ran;")
    lines.append("    *sink = local;")
    lines.append("}")
    return "\n".join(lines)


def main():
    r_values = list(range(0, 101, 2))
    out = HEADER
    for R in r_values:
        out += gen_function(R)
        out += "\n\n"

    with open("random_update.c", "w") as f:
        f.write(out)

    print(f"Generated random_update.c with {len(r_values)} functions.")


if __name__ == "__main__":
    main()
